function ensureClimateEntity(config) {
  if (!config?.entity) {
    throw new Error("You need to define a climate entity");
  }
}

function normalizeHeatingControlConfig(config) {
  return {
    min_temp: 16,
    max_temp: 28,
    step: 0.5,
    background_start: "#ffa20f",
    background_end: "#ff9800",
    slider_orientation: "vertical",
    slider_orientation_mobile: null,
    slider_orientation_desktop: null,
    desktop_layout: "standard",
    heating_on_mode: "heat",
    history_range: "24h",
    ...config
  };
}

// cards/heating-control-card/i18n.js
function getTranslationOverrides(sectionKey) {
  if (typeof window === "undefined") {
    return null;
  }

  const overrides = window.haHeatDesignTranslations?.[sectionKey];
  if (!overrides || typeof overrides !== "object") {
    return null;
  }

  return overrides;
}

function mergeTranslationMaps(baseTranslations, overrideTranslations) {
  if (!overrideTranslations) {
    return baseTranslations;
  }

  const mergedTranslations = { ...baseTranslations };

  Object.entries(overrideTranslations).forEach(([languageCode, overrideValues]) => {
    if (!overrideValues || typeof overrideValues !== "object") {
      return;
    }

    mergedTranslations[languageCode] = {
      ...(baseTranslations[languageCode] || {}),
      ...overrideValues
    };
  });

  return mergedTranslations;
}

function getCardSectionTranslations(sectionKey) {
  return mergeTranslationMaps(getSectionTranslations(sectionKey), getTranslationOverrides(sectionKey));
}

// cards/heating-control-card/services.js
async function setClimateTemperature(hass, entityId, temperature) {
  return hass.callService("climate", "set_temperature", {
    entity_id: entityId,
    temperature
  });
}

async function setClimateHvacMode(hass, entityId, hvacMode) {
  return hass.callService("climate", "set_hvac_mode", {
    entity_id: entityId,
    hvac_mode: hvacMode
  });
}

